update.value:


	UPDATE IBS.T3_BRANCH_DX_ZB
	SET	
		ZB_NM=@{ZB_NM}
	   ,SCORE =@{SCORE}
       ,MODIFY_PEOPLE=#{user_id}
       ,MODIFY_TIME=#{current_time}
       ,MODIFY_IP=#{ip}

	WHERE BRANCH_ORG_ID = @{BRANCH_ORG_ID__old} 
	AND YEAR=@{YEAR__old}
	AND EXAM_Q=@{EXAM_Q__old}
	AND EFF_FLAG=1
	AND PROJCT_NM=@{PROJCT_NM__old}
	AND ZB_NM=@{ZB_NM__old}
	;

insert.value:


   INSERT INTO IBS.T3_BRANCH_DX_ZB (
	 YEAR
	,EXAM_Q
	,BRANCH_ORG_ID
	,BRANCH_ORG_NM
	,PROJCT_NM
	,ZB_NM
	,SCORE
	,EFF_FLAG
	,MODIFY_PEOPLE
	,MODIFY_TIME
	,MODIFY_IP

	,MEASURE_DT
	)
	values(
	@{YEAR}
	,@{EXAM_Q}
	,@{BRANCH_ORG_ID}
	,@{BRANCH_ORG_NM}
	,@{PROJCT_NM}
	,@{ZB_NM}
	,@{SCORE}
	,'1'
	,#{user_id}
	,#{current_time}
	,#{ip}

	,@{YEAR}||(case @{EXAM_Q} when '01' then '-03-31' when '02' then '-06-30' when '03' then '-09-30' when '04' then '-12-31' else '-01-01' end)
	)
	;

sql.delete:







delete from IBS.T3_BRANCH_DX_ZB 
WHERE BRANCH_ORG_ID = @{BRANCH_ORG_ID__old} 
	AND YEAR=@{YEAR__old}
	AND EXAM_Q=@{EXAM_Q__old}
	AND EFF_FLAG=0
	AND PROJCT_NM=@{PROJCT_NM__old}
	AND ZB_NM=@{ZB_NM__old}
;	
UPDATE IBS.T3_BRANCH_DX_ZB
SET EFF_FLAG='0'
	,MODIFY_PEOPLE=#{user_id}
	,MODIFY_TIME=#{current_time}
	,MODIFY_IP=#{ip}
	,REMARK=@{REMARK}
WHERE BRANCH_ORG_ID = @{BRANCH_ORG_ID__old} 
AND YEAR=@{YEAR__old}
AND EXAM_Q=@{EXAM_Q__old}
AND EFF_FLAG=1
AND PROJCT_NM=@{PROJCT_NM__old}
AND ZB_NM=@{ZB_NM__old}
;

