UPDATE IBS.T3_BRANCH_DX_ZB
SET STUS='3'
	, VERIFY_TIME=#{current_time1}
	, VERIFY_PEOPLE=#{user_id}     
	, VER_REMARK=coalesce(VER_REMARK,'')||'审批时间'||#{current_time1}||'审批工号'||#{user_id}||'审批理由页面批复通过。'                        					
WHERE BRANCH_ORG_ID = @{param_brachOrgId} 
AND YEAR=@{param_year}
AND EXAM_Q=@{param_examQ}
AND EFF_FLAG='1'
and STUS='1'
AND PROJCT_NM=@{param_proNm}
AND ZB_NM=@{param_zbNm}
;

