String enPROJCT_NM=StringUtil.encodeString(StringUtil.encodeString(PROJCT_NM));

String btnsh_ztEvent="if(confirm('提交后数据将不能修改，是否确认提交?')){invokeComponentSqlActionButton('branch_dx_ver','select','button1',{param_year:'"+YEAR+"', param_brachOrgId:'"+BRANCH_ORG_ID+"',param_examQ:'"+EXAM_Q_PARM+"',param_proNm:'"+PROJCT_NM+"',param_zbNm:'"+ZB_NM+"'},true,refreshPage)}";
String btnUnsh_ztEvent="wx_winpage('ShowReport.wx?PAGEID=branch_dx_verNo&YEAR="+YEAR+"&EXAM_Q="+EXAM_Q_PARM+"&BRANCH_ORG_ID="+BRANCH_ORG_ID+"&enPROJCT_NM="+enPROJCT_NM+"&enZB_NM="+enZB_NM+"',{width:550,height:350});art.dialog.close();";


if(STUS.equals("3")){
	sh_zt_btn="";
}else{
	sh_zt_btn="<input type=\"button\" class=\""+btnsh_ztCls+"\" value=\"通过\" onclick=\""+btnsh_ztEvent+"\">";
	sh_zt_btn=sh_zt_btn+"<input type=\"button\" class=\""+btnUnsh_ztCls+"\" value=\"不通过\"   onclick=\""+btnUnsh_ztEvent+"\">";
}

