sql.update:






UPDATE IBS.T3_BRANCH_DX_ZB
SET STUS='2'
	, VERIFY_TIME=#{current_time1}
	, VERIFY_PEOPLE=#{user_id}     
	, VER_REMARK=coalesce(VER_REMARK,'')||'审批时间'||#{current_time1}||'审批工号'||#{user_id}||@{REMARK}
	, REMARK=@{REMARK}                       					
WHERE BRANCH_ORG_ID = @{BRANCH_ORG_ID__old} 
AND YEAR=@{YEAR__old}
AND EXAM_Q=@{EXAM_Q__old}
AND EFF_FLAG=1
AND PROJCT_NM=@{PROJCT_NM__old}
AND ZB_NM=@{ZB_NM__old}
